        return await module.InvokeAsync<string?>(InitMethod, dotNetRef);
    }

    /// <summary>
    /// Persists content to localStorage and returns the formatted save time (HH:MM:SS).
    /// </summary>
    public async ValueTask<string> SaveAsync(string content)
