const STORAGE_KEY = 'notepad-content';
const ON_DIRTY_CHANGED = 'OnDirtyChanged';

let dotNetRef;
let abortController;

function onBeforeUnload(e) {
    e.preventDefault();
    e.returnValue = '';
}

export function initialize(ref) {
    dotNetRef = ref;
    abortController = new AbortController();

    // Listen for input so we can track dirty state for beforeunload
    document.querySelector('#notepad-textarea')
        ?.addEventListener('input', () => {
            try {
                dotNetRef.invokeMethodAsync(ON_DIRTY_CHANGED, true);
            } catch { /* circuit disconnected */ }
        }, { signal: abortController.signal });

    return localStorage.getItem(STORAGE_KEY);
}

export function save(content) {
    localStorage.setItem(STORAGE_KEY, content);
    window.removeEventListener('beforeunload', onBeforeUnload);
    const now = new Date();
    return now.toTimeString().split(' ')[0]; // HH:MM:SS
}

export function clear() {
    localStorage.removeItem(STORAGE_KEY);
    window.removeEventListener('beforeunload', onBeforeUnload);
}

export function setBeforeUnload(enable) {
    if (enable) {
        window.addEventListener('beforeunload', onBeforeUnload);
    } else {
        window.removeEventListener('beforeunload', onBeforeUnload);
    }
}

export function dispose() {
    abortController?.abort();
    window.removeEventListener('beforeunload', onBeforeUnload);
}

