+const STORAGE_KEY = 'notepad-content';
+const ON_DIRTY_CHANGED = 'OnDirtyChanged';
+
+let dotNetRef;
+let abortController;
+
+function onBeforeUnload(e) {
+    e.preventDefault();
+    e.returnValue = '';
+}
+
+export function initialize(ref) {
+    dotNetRef = ref;
+    abortController = new AbortController();
