@page "/notepad"
@inject IJSRuntime JS
@implements IAsyncDisposable

<PageTitle>Notepad</PageTitle>

<h1>Notepad</h1>

<textarea id="notepad-textarea"
          class="form-control mb-3"
          rows="12"
          @bind="_content"
          @bind:event="oninput"></textarea>

<div class="d-flex align-items-center gap-2 mb-3">
    <button class="btn btn-primary" @onclick="SaveNowAsync">Save now</button>
    <button class="btn btn-danger" @onclick="ClearAsync">Clear</button>
    @if (_lastSavedAt is not null)
    {
        <span class="text-muted">Last saved at @_lastSavedAt</span>
    }
</div>

@code {
    private NotepadInterop? _interop;
    private DotNetObjectReference<Notepad>? _dotNetRef;

    private string _content = string.Empty;
    private string? _lastSavedAt;
    private string _savedSnapshot = string.Empty;
    private bool _dirty;
    private Timer? _autoSaveTimer;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _interop = new NotepadInterop(JS);

            var saved = await _interop.InitializeAsync(_dotNetRef);
            if (!string.IsNullOrEmpty(saved))
            {
                _content = saved;
                _savedSnapshot = saved;
                StateHasChanged();
            }

            _autoSaveTimer = new Timer(async _ =>
            {
                if (_dirty)
                {
                    await InvokeAsync(async () =>
                    {
                        await SaveContentAsync();
                        StateHasChanged();
                    });
                }
            }, null, TimeSpan.FromSeconds(30), TimeSpan.FromSeconds(30));
        }
    }

    [JSInvokable]
    public async Task OnDirtyChanged(bool isDirty)
    {
        await InvokeAsync(() =>
        {
            _dirty = _content != _savedSnapshot;
        });
    }

    private async Task SaveNowAsync()
    {
        await SaveContentAsync();
    }

    private async Task SaveContentAsync()
    {
        if (_interop is null) return;

        _lastSavedAt = await _interop.SaveAsync(_content);
        _savedSnapshot = _content;
        _dirty = false;
    }

    private async Task ClearAsync()
    {
        if (_interop is null) return;

        _content = string.Empty;
        _savedSnapshot = string.Empty;
        _lastSavedAt = null;
        _dirty = false;
        await _interop.ClearAsync();
    }

    public async ValueTask DisposeAsync()
    {
        _autoSaveTimer?.Dispose();

        if (_interop is not null)
            await _interop.DisposeAsync();

        _dotNetRef?.Dispose();
    }
}

