    <button class="btn btn-primary" @onclick="SaveNowAsync">Save now</button>
    <button class="btn btn-danger" @onclick="ClearAsync">Clear</button>
    @if (_lastSavedAt is not null)
    {
        <span class="text-muted">Last saved at @_lastSavedAt</span>
    }
</div>

@code {
    private NotepadInterop? _interop;

    private string _content = string.Empty;
    private string? _lastSavedAt;
    private string _savedSnapshot = string.Empty;
    private bool _dirty;
    private Timer? _autoSaveTimer;

    private bool IsDirty => _content != _savedSnapshot;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _interop = new NotepadInterop(JS);

            var saved = await _interop.InitializeAsync();
            if (!string.IsNullOrEmpty(saved))
            {
                _content = saved;
                _savedSnapshot = saved;
                StateHasChanged();
            }

            _autoSaveTimer = new Timer(async _ =>
            {
                if (_dirty)
                {
                    await InvokeAsync(async () =>
                    {
                        await SaveContentAsync();
                        StateHasChanged();
                    });
                }
            }, null, TimeSpan.FromSeconds(30), TimeSpan.FromSeconds(30));
        }
    }

