    {
        await SaveContentAsync();
    }

    private async Task SaveContentAsync()
    {
        if (_interop is null) return;

        _lastSavedAt = await _interop.SaveAsync(_content);
        _savedSnapshot = _content;

        if (_dirty)
        {
            _dirty = false;
            await _interop.SetBeforeUnloadAsync(false);
        }
    }

    private async Task ClearAsync()
    {
        if (_interop is null) return;

        _content = string.Empty;
        _savedSnapshot = string.Empty;
        _lastSavedAt = null;

        if (_dirty)
        {
            _dirty = false;
        }

        await _interop.ClearAsync();
    }

    public async ValueTask DisposeAsync()
    {
        _autoSaveTimer?.Dispose();

        if (_interop is not null)
            await _interop.DisposeAsync();
    }
}

